package ru.memearena.tournament.domain; import jakarta.persistence.*; import java.time.*; import java.util.*; @Entity @Table(name="tournament_vote") public class TournamentVote{ @Id public UUID id; @Column(name="match_id") public UUID matchId; @Column(name="user_id") public UUID userId; @Column(name="selected_meme_id") public UUID selectedMemeId; @Column(name="created_at") public Instant createdAt; protected TournamentVote(){} public TournamentVote(UUID id,UUID m,UUID u,UUID s,Instant now){this.id=id;this.matchId=m;this.userId=u;this.selectedMemeId=s;this.createdAt=now;} }
